from geometry_utils import PI, hypotenuse, circle_area, circle_circumference

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    def area(self) -> float:
        return circle_area(self.radius)

    def perimeter(self) -> float:
        return circle_circumference(self.radius)

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class RightTriangle(Shape):
    base: float
    height: float

    def __init__(self, base: float, height: float):
        super().__init__("RightTriangle")
        self.base = base
        self.height = height

    def area(self) -> float:
        return 0.5 * self.base * self.height

    def perimeter(self) -> float:
        hyp: float = hypotenuse(self.base, self.height)
        return self.base + self.height + hyp
